cpp
// Offset is at the start of the table instance
const int32_t soffset =
reinterpret_cast<const int32_t>(table_start_);

cpp
// soffset is negative, VTable resides before Table
const VTable* vtable =
reinterpret_cast<const VTable*>(table_start_ + soffset);

cpp
// field_id indexes into the vtable's offset array
uint16_t offset = vtable->field_offsets[field_id];

cpp
// If offset is 0, field is absent
if (offset == 0) {
return default_value;
}

cpp
// Final pointer: base address + positive offset
const uint8_t* field_ptr = table_start_ + offset;

cpp
T value;
std::memcpy(&value, field_ptr, sizeof(T));
return value;

cpp
// Fallback for schema evolution
return default_value;
